export interface QuestionOption {
  label: string;
  value: number;
  i18n?: { fr?: string; es?: string; zh?: string };
}

export interface Question {
  id: string;
  text: string;
  options: QuestionOption[];
  reverseScore?: boolean;
  i18n?: { fr?: string; es?: string; zh?: string };
}

export interface ScoreInterpretation {
  min: number;
  max: number;
  severity: "minimal" | "low" | "mild" | "moderate" | "moderately-severe" | "high" | "severe" | "normal";
  label: string;
  description: string;
  recommendation: string;
  isHigh: boolean;
  i18n?: {
    fr?: { label?: string; description?: string; recommendation?: string };
    es?: { label?: string; description?: string; recommendation?: string };
    zh?: { label?: string; description?: string; recommendation?: string };
  };
}

export interface Test {
  id: string;
  name: string;
  shortName: string;
  description: string;
  about: string;
  category: string;
  type: "screening" | "self-assessment";
  timeMinutes: number;
  color: string;
  icon: string;
  questions: Question[];
  scoringNote?: string;
  scoring: {
    maxScore: number;
    interpretations: ScoreInterpretation[];
  };
  i18n?: {
    fr?: { name?: string; shortName?: string; description?: string; about?: string; category?: string };
    es?: { name?: string; shortName?: string; description?: string; about?: string; category?: string };
    zh?: { name?: string; shortName?: string; description?: string; about?: string; category?: string };
  };
}

