      es: { name: "Autoevaluación del Agotamiento Laboral (MBI Simplificado)", shortName: "Evaluación de Agotamiento", description: "Una evaluación simplificada de síntomas de agotamiento laboral basada en el Inventario de Burnout de Maslach.", about: "Basado en el Inventario de Maslach, esta evaluación mide tres aspectos clave del agotamiento: agotamiento emocional, despersonalización y reducción del logro personal.", category: "Agotamiento laboral" },
      zh: { name: "职业倦怠自我评估（MBI简化版）", shortName: "职业倦怠评估", description: "基于马斯拉奇倦怠量表的职业倦怠症状简化评估。", about: "基于马斯拉奇倦怠量表，本评估测量职业倦怠的三个关键方面：情绪耗竭、去人格化（疏离）和个人成就感降低。", category: "职业倦怠" },
