      es: { name: "Índice de Gravedad del Insomnio (ISI)", shortName: "Índice de Gravedad del Insomnio", description: "Una medida validada de los síntomas de insomnio y su impacto.", about: "El ISI es una medida breve de la gravedad del insomnio. Evalúa las dificultades para conciliar el sueño, el mantenimiento del sueño, el despertar temprano, la satisfacción con el sueño y el impacto en el funcionamiento diurno.", category: "Sueño" },
      zh: { name: "失眠严重程度指数（ISI）", shortName: "失眠严重程度指数", description: "失眠症状及其影响的有效测量工具。", about: "ISI是失眠严重程度的简短筛查测量。它评估入睡困难、睡眠维持、早醒、睡眠满意度以及睡眠问题对日间功能的影响。", category: "睡眠" },
