export function getTest(id: string): Test | undefined {
  return tests.find((t) => t.id === id);
}

export function calculateScore(test: Test, answers: Record<string, number>): number {
  return Object.values(answers).reduce((sum, val) => sum + val, 0);
}

export function getInterpretation(test: Test, score: number): ScoreInterpretation | undefined {
  return test.scoring.interpretations.find(
    (i) => score >= i.min && score <= i.max
  );
}
